import json
from collections import Counter

with open(locals()['var_function-call-17235522576117083875'], 'r') as f:
    papers = json.load(f)

print(f"Total papers: {len(papers)}")

keyword_counter = Counter()

for p in papers:
    text = p.get('text', '').lower()
    kwd_start = text.find('author keywords')
    if kwd_start == -1:
        kwd_start = text.find('keywords')

    if kwd_start != -1:
        # Try to find end
        candidates = []
        for marker in ['acm classification', 'introduction', 'general terms', 'abstract', 'ccs concepts']:
            idx = text.find(marker, kwd_start + 15)
            if idx != -1:
                candidates.append(idx)

        if candidates:
            kwd_end = min(candidates)
        else:
            kwd_end = kwd_start + 300

        block = text[kwd_start:kwd_end]
        # remove "author keywords" or "keywords" label
        block = block.replace('author keywords', '').replace('keywords', '').strip()

        # Split by ; or , or \n
        parts = block.replace('\n', ';').replace(',', ';').split(';')
        for part in parts:
            k = part.strip()
            if k and len(k) > 2:
                keyword_counter[k] += 1

print("__RESULT__:")
print(json.dumps({
    "top_keywords": keyword_counter.most_common(50)
}))

